class Solution:
    def maxSubstrings(self, word: str) -> int:
        def backtrack(start, end, count):
            if start >= len(word):
                return count
            max_count = count
            for i in range(start + 3, len(word) + 1):
                if word[start] == word[i - 1]:
                    max_count = max(max_count, backtrack(i, end, count + 1))
            return max(max_count, backtrack(start + 1, end, count))

        return backtrack(0, len(word), 0)
